module bin_to_gray(
    input [7:0] invalid_binary,
    output reg [7:0] gray
);

always @(*) begin
    gray[7] = invalid_binary[7];
    gray[6] = invalid_binary[7] ^ invalid_binary[6];
    gray[5] = invalid_binary[6] ^ invalid_binary[5];
    gray[4] = invalid_binary[5] ^ invalid_binary[4];
    gray[3] = invalid_binary[4] ^ invalid_binary[3];
    gray[2] = invalid_binary[3] ^ invalid_binary[2];
    gray[1] = invalid_binary[2] ^ invalid_binary[1];
    gray[0] = invalid_binary[1] ^ invalid_binary[0];
end

endmodule
